import React, { useState, useEffect } from "react";
import axios from "axios";

const Home = () => {
  const [vehicles, setVehicles] = useState([]);
  const [filteredVehicles, setFilteredVehicles] = useState([]);
  const [selectedType, setSelectedType] = useState("all");
  const [types, setTypes] = useState([]);

  useEffect(() => {
    const fetchVehicles = async () => {
      try {
        const res = await axios.get("http://localhost:8070/api/vehicles");

        const available = res.data.filter(
          (v) => v.status === "available"
        );

        setVehicles(available);x
        setFilteredVehicles(available);

        // Extract unique vehicle types dynamically
        const uniqueTypes = [
          ...new Set(available.map((v) => v.type).filter(Boolean)),
        ];
        setTypes(uniqueTypes);
      } catch (err) {
        console.error("Error fetching vehicles", err);
      }
    };

    fetchVehicles();
  }, []);

  // Handle filter change
  const handleFilterChange = (e) => {
    const value = e.target.value;
    setSelectedType(value);

    if (value === "all") {
      setFilteredVehicles(vehicles);
    } else {
      setFilteredVehicles(
        vehicles.filter((v) => v.type === value)
      );
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>AutoPulse Inventory</h2>

      {/* ✅ Filter Dropdown */}
      <div style={{ marginBottom: 20 }}>
        <label style={{ marginRight: 10 }}>
          Filter by Type:
        </label>

        <select
          value={selectedType}
          onChange={handleFilterChange}
          style={{ padding: 8 }}
        >
          <option value="all">All</option>
          {types.map((t) => (
            <option key={t} value={t}>
              {t}
            </option>
          ))}
        </select>
      </div>

      {/* Vehicle Grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(3, 1fr)",
          gap: "15px",
        }}
      >
        {filteredVehicles.map((v) => (
          <div
            key={v._id}
            style={{
              border: "1px solid #ddd",
              padding: "15px",
              borderRadius: "8px",
            }}
          >
            <h3>
              {v.brand} {v.type} ({v.year})
            </h3>

            <p>
              <strong>Price:</strong> LKR{" "}
              {Number(v.price).toLocaleString()}
            </p>

            <p>
              <strong>Status:</strong>
              <span
                style={{
                  color:
                    v.status === "sold"
                      ? "red"
                      : "green",
                }}
              >
                {" "}
                {v.status}
              </span>
            </p>
          </div>
        ))}
      </div>

      {filteredVehicles.length === 0 && (
        <p style={{ marginTop: 20 }}>
          No vehicles found for selected type.
        </p>
      )}
    </div>
  );
};

export default Home;
